// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Helper function to get weather icon based on condition
function getWeatherIcon(condition: string) {
  const conditionLower = condition.toLowerCase();

  if (conditionLower.includes('sun') || conditionLower.includes('clear')) {
    return <Icon name="sun" size={48} color="var(--ggui-color-primary-600)" />;
  } else if (conditionLower.includes('cloud')) {
    return <Icon name="cloud" size={48} color="var(--ggui-color-onSurfaceVariant)" />;
  } else if (conditionLower.includes('rain')) {
    return <Icon name="cloud-rain" size={48} color="var(--ggui-color-primary-500)" />;
  } else if (conditionLower.includes('snow')) {
    return <Icon name="snowflake" size={48} color="var(--ggui-color-primary-200)" />;
  } else if (conditionLower.includes('storm') || conditionLower.includes('thunder')) {
    return <Icon name="cloud-lightning" size={48} color="var(--ggui-color-warning-600)" />;
  } else if (conditionLower.includes('wind')) {
    return <Icon name="wind" size={48} color="var(--ggui-color-primary-400)" />;
  } else if (conditionLower.includes('fog') || conditionLower.includes('mist')) {
    return <Icon name="cloud-fog" size={48} color="var(--ggui-color-onSurfaceVariant)" />;
  }

  // Default to partly cloudy
  return <Icon name="cloud-sun" size={48} color="var(--ggui-color-primary-500)" />;
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Current Weather Card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Location and Condition */}
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
            </Stack>

            {/* Weather Icon and Temperature */}
            <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="center">
              {/* Condition Icon */}
              <Box>
                {getWeatherIcon(props.condition)}
              </Box>

              {/* Temperature */}
              <Stack gap="var(--ggui-spacing-1)" align="start">
                <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">
                  {props.temperature}°{props.unit}
                </Text>
              </Stack>
            </Stack>

            <Divider orientation="horizontal" margin="var(--ggui-spacing-4)" color="var(--ggui-color-outlineVariant)" />

            {/* Weather Details */}
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="start">
              {/* Humidity */}
              <Stack gap="var(--ggui-spacing-1)" align="start">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
              </Stack>

              {/* Wind Speed */}
              <Stack gap="var(--ggui-spacing-1)" align="start">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} m/s</Text>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="lg">
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={4} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>

              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" wrap justify="between" align="stretch">
                {props.forecast.map((day, index) => (
                  <Card
                    key={index}
                    shadow="none"
                    padding="var(--ggui-spacing-3)"
                    radius="md"
                    border={false}
                    style={{
                      flex: '1 1 calc(20% - var(--ggui-spacing-2))',
                      minWidth: '80px',
                      background: 'var(--ggui-color-surfaceVariant)',
                      textAlign: 'center',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                      {/* Day Name */}
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        {day.day || `Day ${index + 1}`}
                      </Text>

                      {/* Weather Icon */}
                      <Box>
                        {day.icon ? (
                          typeof day.icon === 'string' && day.icon.length === 1 ? (
                            <Icon name={day.icon} size={24} />
                          ) : (
                            <Icon name={day.icon as string} size={24} />
                          )
                        ) : (
                          <Icon name="sun" size={24} color="var(--ggui-color-primary-600)" />
                        )}
                      </Box>

                      {/* Temperature Range */}
                      <Stack gap="var(--ggui-spacing-1)" align="center">
                        <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">
                          {day.high ? `${day.high}°` : '—'}
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {day.low ? `${day.low}°` : '—'}
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>
                ))}
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

