import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation helpers
  const isValidEmail = (e: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(e);
  };

  const isNameValid = name.trim().length > 0;
  const isEmailValid = email.trim().length > 0 && isValidEmail(email);
  const isSatisfactionValid = satisfaction !== '';
  const isFeaturesValid = features.length > 0;
  const isCommentsValid = true; // optional field

  // Step-specific validation
  const isStep1Valid = isNameValid && isEmailValid;
  const isStep2Valid = isSatisfactionValid;
  const isStep3Valid = isFeaturesValid;
  const isStep4Valid = true; // comments are optional

  // Navigation handlers
  const handleNext = () => {
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = () => {
    if (isStep1Valid && isStep2Valid && isStep3Valid && isStep4Valid) {
      submit({
        name: name.trim(),
        email: email.trim(),
        satisfaction: parseInt(satisfaction, 10),
        features,
        comments: comments.trim(),
      });
    }
  };

  const handleFeatureToggle = (feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  };

  // Determine if Next button should be disabled for current step
  const isNextDisabled = (() => {
    switch (currentStep) {
      case 1:
        return !isStep1Valid;
      case 2:
        return !isStep2Valid;
      case 3:
        return !isStep3Valid;
      case 4:
        return !isStep4Valid;
      default:
        return false;
    }
  })();

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Header with progress indicator */}
        <Stack gap="var(--ggui-spacing-4)" align="stretch">
          <Heading level={2}>Survey Form</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 4
          </Text>
          <Progress value={currentStep} max={4} size="sm" aria-label={`Step ${currentStep} of 4`} aria-valuenow={currentStep} aria-valuemin={1} aria-valuemax={4} />
        </Stack>

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" role="region" aria-label="Step 1: Contact Information">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3}>Contact Information</Heading>
              <Input
                label="Name"
                placeholder="Enter your full name"
                value={name}
                onChange={setName}
                required
                error={name.trim().length === 0 && name.length > 0 ? 'Name is required' : ''}
              />
              <Input
                label="Email"
                type="email"
                placeholder="Enter your email address"
                value={email}
                onChange={setEmail}
                required
                error={
                  email.trim().length > 0 && !isValidEmail(email)
                    ? 'Please enter a valid email address'
                    : email.trim().length === 0 && email.length > 0
                    ? 'Email is required'
                    : ''
                }
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" role="region" aria-label="Step 2: Satisfaction Rating">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: String(index + 1),
                  label,
                }))}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" role="region" aria-label="Step 3: Feature Interests">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3}>Which features interest you?</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Select at least one feature
              </Text>
              <Stack gap="var(--ggui-spacing-3)" align="stretch">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" role="region" aria-label="Step 4: Additional Comments">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Share any additional feedback or comments (optional)"
                value={comments}
                onChange={setComments}
                maxLength={500}
                showCount
                rows={6}
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" role="region" aria-label="Step 5: Review Your Answers">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-3)" align="stretch">
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)" align="stretch">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Name
                    </Text>
                    <Text>{name}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)" align="stretch">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Email
                    </Text>
                    <Text>{email}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)" align="stretch">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Satisfaction Rating
                    </Text>
                    <Text>
                      {satisfaction && props.satisfactionLabels[Math.min(Math.max(parseInt(satisfaction, 10) - 1, 0), props.satisfactionLabels.length - 1)]}
                    </Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)" align="stretch">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Features of Interest
                    </Text>
                    <Stack direction="horizontal" gap="var(--ggui-spacing-2)" wrap>
                      {features.map((feature) => (
                        <Badge key={feature} variant="primary">
                          {feature}
                        </Badge>
                      ))}
                    </Stack>
                  </Stack>
                </Box>
                {comments.trim().length > 0 && (
                  <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                    <Stack gap="var(--ggui-spacing-2)" align="stretch">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Comments
                      </Text>
                      <Text>{comments}</Text>
                    </Stack>
                  </Box>
                )}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between" align="center">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
            {currentStep < 5 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={isNextDisabled}
              >
                Next
              </Button>
            )}
            {currentStep === 5 && (
              <Button
                variant="primary"
                onClick={handleSubmit}
              >
                Submit
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}

