// Helper component: Column with tasks
function KanbanColumn({
  column,
  tasks,
  onAddTask,
  onMoveTask,
  onEditTask,
}: {
  column: Props['columns'][0];
  tasks: Props['tasks'];
  onAddTask: (columnId: string, title: string) => void;
  onMoveTask: (taskId: string, toColumn: string) => void;
  onEditTask: (taskId: string, newTitle: string) => void;
}) {
  const [showAddForm, setShowAddForm] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const handleAddTask = useCallback(() => {
    if (newTaskTitle.trim()) {
      onAddTask(column.id || '', newTaskTitle);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setShowAddForm(false);
    }
  }, [newTaskTitle, newTaskPriority, column.id, onAddTask]);

  const columnTasks = tasks.filter((t) => t.column === column.id);

  return (
    <Card
      padding="var(--ggui-spacing-4)"
      shadow="sm"
      radius="lg"
      border={true}
    >
      <Stack gap="var(--ggui-spacing-3)">
        {/* Column Header */}
        <Box
          paddingBottom="var(--ggui-spacing-2)"
          borderRadius="0"
          style={{ borderBottom: '2px solid var(--ggui-color-outlineVariant)' }}
        >
          <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-1)" align="center">
              <Text variant="label" weight="semibold">
                {column.name}
              </Text>
              <Badge variant="default" size="sm" pill={true}>
                {columnTasks.length}
              </Badge>
            </Stack>
          </Row>
        </Box>

        {/* Task Cards */}
        <Stack gap="var(--ggui-spacing-2)" style={{ minHeight: '300px' }}>
          {columnTasks.map((task) => (
            <TaskCard
              key={task.id}
              task={task}
              onMove={onMoveTask}
              onEdit={onEditTask}
            />
          ))}
        </Stack>

        {/* Add Task Button / Form */}
        {showAddForm ? (
          <Stack gap="var(--ggui-spacing-2)">
            <Input
              label="Task title"
              placeholder="Enter task title..."
              value={newTaskTitle}
              onChange={setNewTaskTitle}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleAddTask();
                if (e.key === 'Escape') {
                  setNewTaskTitle('');
                  setNewTaskPriority('medium');
                  setShowAddForm(false);
                }
              }}
              autoFocus
            />
            <Select
              label="Priority"
              value={newTaskPriority}
              onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
              options={[
                { value: 'low', label: 'Low' },
                { value: 'medium', label: 'Medium' },
                { value: 'high', label: 'High' },
              ]}
            />
            <Row gap="var(--ggui-spacing-2)" justify="end">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => {
                  setNewTaskTitle('');
                  setNewTaskPriority('medium');
                  setShowAddForm(false);
                }}
              >
                Cancel
              </Button>
              <Button
                variant="primary"
                size="sm"
                onClick={handleAddTask}
                disabled={!newTaskTitle.trim()}
              >
                Add Task
              </Button>
            </Row>
          </Stack>
        ) : (
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setShowAddForm(true)}
            fullWidth={true}
          >
            + Add Task
          </Button>
        )}
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state for tasks (merged with incoming stream events)
  const [tasks, setTasks] = useState<Props['tasks']>(props.tasks || []);

  // Merge incoming stream changes into local state
  useEffect(() => {
    if (taskChanged.latest?.task) {
      const updatedTask = taskChanged.latest.task;
      setTasks((prevTasks) => {
        const index = prevTasks.findIndex((t) => t.id === updatedTask.id);
        if (taskChanged.latest?.action === 'delete' && index >= 0) {
          return prevTasks.filter((t) => t.id !== updatedTask.id);
        }
        if (index >= 0) {
          const updated = [...prevTasks];
          updated[index] = { ...updated[index], ...updatedTask };
          return updated;
        }
        if (taskChanged.latest?.action === 'create') {
          return [...prevTasks, updatedTask];
        }
        return prevTasks;
      });
    }
  }, [taskChanged.latest]);

  // Sync props.tasks on mount
  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Handlers
  const handleAddTask = useCallback(
    (columnId: string, title: string, priority: 'low' | 'medium' | 'high' = 'medium') => {
      const newTask: Props['tasks'][0] = {
        id: `task-${Date.now()}`,
        title,
        column: columnId,
        priority,
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({
        action: 'create',
        taskId: newTask.id || '',
        data: { column: columnId },
      });
    },
    [taskUpdate]
  );

  const handleMoveTask = useCallback(
    (taskId: string, toColumn: string) => {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t))
      );
      taskUpdate({
        action: 'move',
        taskId,
        data: { column: toColumn },
      });
    },
    [taskUpdate]
  );

  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
      );
      taskUpdate({
        action: 'edit',
        taskId,
        data: { column: tasks.find((t) => t.id === taskId)?.column || '' },
      });
    },
    [taskUpdate, tasks]
  );

  // Compute summary stats
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box background="var(--ggui-color-primary-50)" padding="var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-lg)">
          <Row gap="var(--ggui-spacing-4)" align="center" justify="between">
            <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="center">
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Text variant="label" weight="semibold" color="var(--ggui-color-primary-900)">
                  Total Tasks:
                </Text>
                <Badge variant="primary" size="md" pill={true}>
                  {totalTasks}
                </Badge>
              </Stack>
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Text variant="label" weight="semibold" color="var(--ggui-color-primary-900)">
                  Completed:
                </Text>
                <Badge variant="success" size="md" pill={true}>
                  {completedTasks}
                </Badge>
              </Stack>
            </Stack>
            {totalTasks > 0 && (
              <Progress
                value={completedTasks}
                max={totalTasks}
                variant="success"
                size="md"
              />
            )}
          </Row>
        </Box>

        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" wrap={true}>
          {props.columns.map((col) => (
            <Box key={col.id} style={{ flex: '1 1 350px', minWidth: '350px' }}>
              <KanbanColumn
                column={col}
                tasks={tasks}
                onAddTask={handleAddTask}
                onMoveTask={handleMoveTask}
                onEditTask={handleEditTask}
              />
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

