// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [messages, setMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<{ [key: string]: boolean }>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Handle new messages from stream
  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      setTypingUsers((prev) => ({
        ...prev,
        [typing.latest!.sender || 'unknown']: typing.latest!.active ?? false,
      }));
    }
  }, [typing.latest]);

  // Send message handler
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      setMessages((prev) => [
        ...prev,
        { sender: props.currentUser, text: inputValue, timestamp },
      ]);
      setInputValue('');
    }
  }, [inputValue, sendMessage, props.currentUser]);

  // Handle Enter key to send
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ text?: string; timestamp?: string }> }> = [];
    messages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push({ text: msg.text, timestamp: msg.timestamp });
      } else {
        groups.push({ sender: msg.sender, messages: [{ text: msg.text, timestamp: msg.timestamp }] });
      }
    });
    return groups;
  }, [messages]);

  // Get active typing users (excluding current user)
  const activeTypingUsers = Object.entries(typingUsers)
    .filter(([sender, active]) => active && sender !== props.currentUser)
    .map(([sender]) => sender);

  // Format timestamp
  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    try {
      return new Date(timestamp).toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        hour12: true,
      });
    } catch {
      return '';
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" radius="lg" padding="var(--ggui-spacing-6)" border={true}>
        <Stack gap="var(--ggui-spacing-6)" direction="vertical">
          {/* Header */}
          <Row justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
              <Heading level={3}>{props.title}</Heading>
              <Badge variant="primary" size="sm">
                {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
              </Badge>
            </Stack>
          </Row>

          <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

          {/* Message List */}
          <Box
            paddingY="var(--ggui-spacing-4)"
            paddingX="var(--ggui-spacing-2)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
            style={{
              maxHeight: '400px',
              overflowY: 'auto',
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--ggui-spacing-4)',
            }}
          >
            {groupedMessages.length === 0 ? (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
                No messages yet. Start the conversation!
              </Text>
            ) : (
              groupedMessages.map((group, idx) => {
                const isCurrentUser = group.sender === props.currentUser;
                return (
                    <Box
                      key={idx}
                      padding="var(--ggui-spacing-2)"
                      style={{
                        maxWidth: '70%',
                        alignSelf: isCurrentUser ? 'flex-end' : 'flex-start',
                      }}
                    >
                      <Stack
                        direction="vertical"
                        gap="var(--ggui-spacing-1)"
                        align={isCurrentUser ? 'end' : 'start'}
                      >
                        {group.sender && (
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" size="sm">
                            {group.sender}
                          </Text>
                        )}
                        {group.messages.map((msg, msgIdx) => (
                          <Box
                            key={msgIdx}
                            padding="var(--ggui-spacing-3)"
                            background={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-600)'
                                : 'var(--ggui-color-surfaceVariant)'
                            }
                            borderRadius="var(--ggui-shape-radius-md)"
                          >
                            <Stack direction="vertical" gap="var(--ggui-spacing-1)" align="stretch">
                              <Text
                                variant="body"
                                color={
                                  isCurrentUser
                                    ? 'white'
                                    : 'var(--ggui-color-onSurface)'
                                }
                              >
                                {msg.text || ''}
                              </Text>
                              {msg.timestamp && (
                                <Text
                                  variant="caption"
                                  color={
                                    isCurrentUser
                                      ? 'rgba(255, 255, 255, 0.7)'
                                      : 'var(--ggui-color-onSurfaceVariant)'
                                  }
                                >
                                  {formatTime(msg.timestamp)}
                                </Text>
                              )}
                            </Stack>
                          </Box>
                        ))}
                      </Stack>
                    </Box>
                );
              })
            )}
            {/* Typing Indicator */}
            {activeTypingUsers.length > 0 && (
              <Box paddingX="var(--ggui-spacing-3)" paddingY="var(--ggui-spacing-2)">
                <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                  <Spinner size={16} color="var(--ggui-color-primary-600)" />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {activeTypingUsers.length === 1
                      ? `${activeTypingUsers[0]} is typing...`
                      : `${activeTypingUsers.join(', ')} are typing...`}
                  </Text>
                </Stack>
              </Box>
            )}
            <div ref={messagesEndRef} />
          </Box>

          {/* Input Area */}
           {/* Input Area */}
           <Stack direction="vertical" gap="var(--ggui-spacing-3)" align="stretch">
              <TextArea
                label="Message"
                placeholder="Type a message... (Shift+Enter for newline)"
                value={inputValue}
