                onKeyDown={handleKeyDown}
                rows={3}
              />
             <Box
               paddingY="var(--ggui-spacing-2)"
               style={{ display: 'flex', gap: 'var(--ggui-spacing-2)' }}
             >
               <Button
                 variant="primary"
                 fullWidth
                 disabled={!inputValue.trim()}
                 onClick={handleSendMessage}
