export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State to track recently updated stocks for animation
  const [updatedStocks, setUpdatedStocks] = useState<Set<string>>(new Set());
  const updateTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Last update timestamp
  const [lastUpdatedTime, setLastUpdatedTime] = useState<Date | null>(null);

  // Merge stream updates into stocks
  const displayStocks = useMemo(() => {
    if (!priceUpdate.latest) return props.stocks || [];

    const stockMap = new Map(props.stocks?.map(s => [s.symbol, s]) || []);
    const updated = { ...priceUpdate.latest };

    if (updated.symbol && stockMap.has(updated.symbol)) {
      const existing = stockMap.get(updated.symbol)!;
      stockMap.set(updated.symbol, {
        ...existing,
        price: updated.price !== undefined ? updated.price : existing.price,
        change: updated.change !== undefined ? updated.change : existing.change,
        changePercent: updated.changePercent !== undefined ? updated.changePercent : existing.changePercent,
      });
    }

    return Array.from(stockMap.values());
  }, [props.stocks, priceUpdate.latest]);

  // Handle price updates for animation
  useEffect(() => {
    if (priceUpdate.latest?.symbol) {
      setUpdatedStocks(prev => new Set([...prev, priceUpdate.latest.symbol!]));
      setLastUpdatedTime(new Date());

      if (updateTimeoutRef.current) clearTimeout(updateTimeoutRef.current);
      updateTimeoutRef.current = setTimeout(() => {
        setUpdatedStocks(new Set());
      }, 700);
    }
  }, [priceUpdate.latest]);

  useEffect(() => {
    return () => {
      if (updateTimeoutRef.current) clearTimeout(updateTimeoutRef.current);
    };
  }, []);

  // Format time for display
  const formattedTime = lastUpdatedTime
    ? lastUpdatedTime.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' })
    : 'Never';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Header with title and last updated timestamp */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)">
          <Stack gap="var(--ggui-spacing-2)" align="start">
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated:
              </Text>
              <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-600)">
                {formattedTime}
              </Text>
              {marketStatus.latest && (
                <>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    •
                  </Text>
                  <Badge
                    variant={
                      marketStatus.latest.status === 'open'
                        ? 'success'
                        : marketStatus.latest.status === 'closed'
                        ? 'error'
                        : 'warning'
                    }
                    size="sm"
                  >
                    {marketStatus.latest.status === 'open'
                      ? 'Market Open'
                      : marketStatus.latest.status === 'closed'
                      ? 'Market Closed'
                      : marketStatus.latest.status === 'pre-market'
                      ? 'Pre-Market'
                      : 'After Hours'}
                  </Badge>
                </>
              )}
            </Row>
          </Stack>
        </Box>

        {/* Responsive stock grid */}
        {displayStocks && displayStocks.length > 0 ? (
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
              gap: 'var(--ggui-spacing-4)',
            } as React.CSSProperties}
          >

            {displayStocks.map((stock) => (
              <StockCard
                key={stock.symbol || 'unknown'}
                stock={stock}
                isUpdating={updatedStocks.has(stock.symbol || '')}
              />
            ))}
          </div>
        ) : (
          <Alert variant="info" title="No stocks available">
