  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar || props.avatarOptions[0] || '');
  const [role, setRole] = useState(props.initialProfile.role || props.roleOptions[0] || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');

  // Validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = emailRegex.test(email);
  const isStep1Valid = name.trim() !== '' && isEmailValid;

  // Navigation
  const handleNext = useCallback(() => {
    if (step === 1 && isStep1Valid) setStep(2);
    else if (step === 2) setStep(3);
  }, [step, isStep1Valid]);

  const handleBack = useCallback(() => {
    if (step > 1) setStep(step - 1);
  }, [step]);

  const handleComplete = useCallback(() => {
    complete({
      name,
      email,
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [name, email, avatar, role, emailNotifications, theme, complete]);

  // Progress calculation
  const progressPercent = ((step - 1) / 2) * 100;

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with step indicator */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2} color="var(--ggui-color-onSurface)">
            Profile Setup
          </Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Step {step} of 3
          </Text>
          <Progress value={progressPercent} max={100} variant="default" size="md" />
        </Stack>

        {/* Step 1: Profile Setup */}
        {step === 1 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Input
                label="Name"
                value={name}
                onChange={setName}
                placeholder="Enter your name"
                required
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                placeholder="you@example.com"
                required
                error={email && !isEmailValid ? 'Please enter a valid email' : ''}
              />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ marginBottom: 'var(--ggui-spacing-2)' }}>
                  Avatar
                </Text>
                <Row gap="var(--ggui-spacing-3)" justify="start">
                  {props.avatarOptions.map((option) => (
                    <Box
                      key={option}
                      as={Clickable}
                      onClick={() => setAvatar(option)}
                      padding="var(--ggui-spacing-2)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={avatar === option ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                      style={{ cursor: 'pointer', border: avatar === option ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent' }}
                    >
                      <Text size="3xl">{option}</Text>
                    </Box>
                  ))}
                </Row>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {step === 2 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Select
                label="Role"
                value={role}
                onChange={setRole}
                options={props.roleOptions.map((r) => ({ value: r, label: r }))}
              />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ marginBottom: 'var(--ggui-spacing-2)', display: 'block' }}>
                  Notifications
                </Text>
                <Toggle
                  label="Enable email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ marginBottom: 'var(--ggui-spacing-2)', display: 'block' }}>
                  Theme
                </Text>
                <RadioGroup
                  label=""
                  value={theme}
                  onChange={setTheme}
                  options={[
                    { value: 'light', label: 'Light' },
                    { value: 'dark', label: 'Dark' },
                  ]}
                  direction="horizontal"
                />
              </Box>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {step === 3 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3} color="var(--ggui-color-onSurface)">
                Review Your Setup
              </Heading>
              <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name:</Text>
                    <Text color="var(--ggui-color-onSurface)">{name}</Text>
                  </Row>
                  <Row justify="between">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email:</Text>
                    <Text color="var(--ggui-color-onSurface)">{email}</Text>
                  </Row>
                  <Row justify="between">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Avatar:</Text>
                    <Text size="lg">{avatar}</Text>
                  </Row>
                  <Row justify="between">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Role:</Text>
                    <Text color="var(--ggui-color-onSurface)">{role}</Text>
                  </Row>
                  <Row justify="between">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email Notifications:</Text>
                    <Badge variant={emailNotifications ? 'success' : 'default'}>{emailNotifications ? 'Enabled' : 'Disabled'}</Badge>
                  </Row>
                  <Row justify="between">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Theme:</Text>
                    <Text color="var(--ggui-color-onSurface)" style={{ textTransform: 'capitalize' }}>{theme}</Text>
                  </Row>
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={step === 1}
          >
            Go Back
          </Button>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)">
            {step < 3 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={step === 1 && !isStep1Valid}
              >
                Next
              </Button>
            )}
            {step === 3 && (
              <Button
                variant="primary"
                onClick={handleComplete}
              >
                Complete Setup
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}
